import pandas as pd
import os

def verify_targets_from_excel(excel_file, expected_targets, Target="Target"):
    """
    Reads an Excel file, checks if all expected targets are present in the given column.
    Returns a list of missing targets if any.
    """
    # Load Excel
    df = pd.read_excel(excel_file, engine="openpyxl")
    
    if Target not in df.columns:
        raise ValueError(f"Column '{Target}' not found in Excel file. Available columns: {list(df.columns)}")
    
    # Convert the target column to a list of strings
    actual_targets = df[Target].astype(str).tolist()
    
    # Check for missing elements
    missing = [t for t in expected_targets if t not in actual_targets]
    
    if missing:
        print("❌ Missing targets:")
        for m in missing:
            print(f"   - {m}")
    else:
        print("✅ All expected targets are present.")
    
    return missing
	

